css:
.loader {color: var(--loader-color, #9333ea);
  --loader-secondary-color: #f0abfc;
  --loader-bg: #ffffff;
  width: 40px;
  aspect-ratio: 1;
  background: currentColor;
  animation: l1 1s infinite;
}@keyframes l1 {0% {transform: perspective(150px) rotateX( 0deg)}100% {transform: perspective(150px) rotateX(180deg)}}
